(23, 2, 'karanbir@virtualoplossing.com', 'karanbir@virtualoplossing.com,karanbirsingh201198@gmail.com', 'EOD Report: Karan - September 10, 2025', '<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <title>EOD Report: Karan - September 10, 2025</title>\r\n    <style>\r\n        /* Basic responsive styles for email clients that support them */\r\n        @media screen and (max-width: 600px) {\r\n            .content-table {\r\n                width: 100% !important;\r\n            }\r\n        }\r\n        div[style*=\"background-color:#FFEB9C\"] {\r\n  display: none !important;\r\n}\r\n\r\n    </style>\r\n</head>\r\n<body style=\"margin: 0; padding: 0; background-color: #f4f7f6;\">\r\n    <table width=\"100%\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" bgcolor=\"#f4f7f6\">\r\n        <tr>\r\n            <td align=\"center\" style=\"padding: 20px 0;\">\r\n                \r\n                <!-- Main Email Wrapper Table (600px wide) -->\r\n                <table class=\"content-table\" width=\"600\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" align=\"center\" style=\"background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 15px rgba(0,0,0,0.1);\">\r\n                    \r\n                    <!-- Header Section -->\r\n                    <tr>\r\n                        <td style=\"padding: 30px 40px; border-bottom: 1px solid #eeeeee;\">\r\n                            <!-- Your company logo -->\r\n                            <img src=\"https://virtualoplossing.com/wp-content/themes/blankslate/assets/img/virtual-oplossing-logo.svg\" alt=\"VirtualOplossing Logo\" width=\"180\" style=\"display: block;\">\r\n                        </td>\r\n                    </tr>\r\n                    \r\n                    <!-- Body Content Section -->\r\n                    <tr>\r\n                        <td style=\"padding: 40px 40px 30px 40px; font-family: Arial, Helvetica, sans-serif; font-size: 16px; line-height: 1.6; color: #333;\">\r\n                            \r\n                            <!-- This is where the dynamic EOD report content will be injected -->\r\n                            <p>Hello Team,</p>\r\n<p>Here is my End-of-Day (EOD) report summarizing my work today. Please note that the time allocations mentioned below are approximate.</p>\r\n<h3>VoPharma Website Development</h3>\r\n<ul>\r\n<li><strong>Image Updates:</strong> Replaced sales representative images with production-quality images.</li>\r\n<li><strong>Page Speed Optimization:</strong> Addressed further page speed reductions resulting from concurrent developer work.</li>\r\n<li><strong>New Page Development:</strong> Created the following pages as assigned by Neeraj Sir and Nishant Sir:\r\n<ul>\r\n<li>Mohali page</li>\r\n<li>Baddi page</li>\r\n<li>Pharmaceutical Manufacturing Companies in Kolkata</li>\r\n<li>Medicine Manufacturing Company in Lucknow</li>\r\n<li>Pharmaceutical Company in Panchkula</li>\r\n<li>Pharma Manufacturing Company in Chandigarh</li>\r\n</ul>\r\n</li>\r\n<li><strong>Contact Form Development:</strong> Developed and implemented a contact form on the \"All Services\" and Baddi pages, verifying successful form submissions.</li>\r\n<li><strong>Contact Us Page Redesign:</strong> Redesigned the contact us page and resolved alignment issues.</li>\r\n<li><strong>Third Party Manufacturer Page:</strong> Commenced work on the \"Third Party Manufacturer in Maharashtra\" page.</li>\r\n</ul>\r\n<h3>MAX Project</h3>\r\n<ul>\r\n<li><strong>Dashboard Design:</strong> Worked on the design of the MAX project dashboard.</li>\r\n<li><strong>Data Entry:</strong> Added three demo posts.</li>\r\n<li><strong>About Us Page:</strong> Completed the \"About Us\" page and started work on the login/logout form popup.</li>\r\n</ul>\r\n<h3>Other Projects</h3>\r\n<ul>\r\n<li><strong>Carpet Cleaning Christchurch Website:</strong> Worked briefly on services pages and account setup.</li>\r\n<li><strong>VoTracker:</strong> Currently testing the VoTracker application.</li>\r\n</ul>\r\n<p>Please let me know if you have any questions.</p>\r\n<p>Sincerely,<br>Karan</p>\r\n<p><em>Disclaimer: The time allocations provided in this report are approximate and for illustrative purposes only. This is not an exact record of time spent. This report was generated with the assistance of AI and does not reflect precisely tracked time.</em></p>                            \r\n                        </td>\r\n                    </tr>\r\n                    \r\n                    <!-- Footer / Signature Section -->\r\n                    <tr>\r\n                        <td style=\"padding: 0;\">\r\n                            \r\n                            <!-- This is where your custom signature from the database will be injected -->\r\n                            <table style=\"background-color: rgb(15, 45, 62); background-image: url(\'\\\'\\\'\'); background-repeat: repeat; padding: 20px; width: 818px; font-family: Arial, sans-serif; height: 130px;\" border=\"0\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding-right: 20px; width: 246.469px;\" align=\"left\"><!-- Logo and Company Info -->\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td><img src=\"https://virtualoplossing.com/wp-content/uploads/2025/06/Virtual-Oplossing-White.svg\" alt=\"Virtual Oplossing Logo\" width=\"180\"></td>\r\n</tr>\r\n<tr>\r\n<td style=\"font-size: 12px; color: #ffffff; padding-top: 5px;\">We deliver your thoughts</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n<td style=\"width: 232.391px;\" align=\"left\"><!-- Personal Information -->\r\n<p style=\"margin: 0; font-size: 14px; color: #38b6ff;\">Regards,</p>\r\n<h3 style=\"margin: 5px 0; font-size: 20px; color: #ffffff; font-weight: bold;\">KARANBIR SINGH</h3>\r\n<p style=\"background-color: #38b6ff; color: #ffffff; font-size: 12px; padding: 5px 10px; border-radius: 4px; display: inline-block; margin: 0;\">CMS Developer</p>\r\n</td>\r\n<td style=\"border-left: 2px solid rgb(255, 255, 255); width: 24.5px; padding-left: 20px;\">&nbsp;</td>\r\n<td style=\"width: 268.641px;\" align=\"left\"><!-- Contact Information -->\r\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\">\r\n<tbody>\r\n<tr>\r\n<td style=\"padding-bottom: 10px;\"><!-- <img src=\"https://i.imgur.com/H5jBvL1.png\" alt=\"Email Icon\" width=\"16\" style=\"vertical-align: middle;\"> --> <a style=\"color: #ffffff; text-decoration: none; font-size: 14px; vertical-align: middle; padding-left: 10px;\" href=\"mailto:karanbir@virtualoplossing.com\">karanbir@virtualoplossing.com</a></td>\r\n</tr>\r\n<tr>\r\n<td><!-- <img src=\"https://i.imgur.com/J3iYnPp.png\" alt=\"Phone Icon\" width=\"16\" style=\"vertical-align: middle;\"> --> <a style=\"color: #ffffff; text-decoration: none; font-size: 14px; vertical-align: middle; padding-left: 10px;\" href=\"tel:+91-7696887976\">+91-7696887976</a></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>                            \r\n                        </td>\r\n                    </tr>\r\n                    \r\n                </table>\r\n\r\n                <!-- Unsubscribe/Info Footer -->\r\n                <table class=\"content-table\" width=\"600\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" align=\"center\" style=\"padding-top: 20px;\">\r\n                    <tr>\r\n                        <td align=\"center\" style=\"font-family: Arial, Helvetica, sans-serif; font-size: 12px; color: #999;\">\r\n                            <p style=\"margin: 0;\">This email was sent automatically from the VO TimeTracker application.</p>\r\n                            <p style=\"margin: 5px 0 0 0;\">VirtualOplossing | 160072, Mohali, Punjab, India</p>\r\n                        </td>\r\n                    </tr>\r\n                </table>\r\n\r\n            </td>\r\n        </tr>\r\n    </table>\r\n    <script><script>\r\ndocument.addEventListener(\"DOMContentLoaded\", function () {\r\n  document.querySelectorAll(\"div\").forEach(function (el) {\r\n    if (el.textContent.includes(\"This email originated from outside of the organization\")) {\r\n      el.style.display = \"none\";\r\n    }\r\n  });\r\n});\r\n</script>\r\n</script>\r\n</body>\r\n</html>', '', 'failed', 'SMTP Error: Could not authenticate.', '2025-09-15 12:43:22');
